    x = list(map(int, input().split()))
    s = []
    for _ in range(n):
        s.append(input().strip())

    from collections import defaultdict
    profile_questions = defaultdict(list)
    for j in range(m):
        mask = 0
        for i in range(n):
            if s[i][j] == '1':
                mask |= (1 << i)
        profile_questions[mask].append(j)

    profiles = list(profile_questions.keys())
    profile_remaining = {mask: len(qs) for mask, qs in profile_questions.items()}

    r = [0] * n
    assignment = {}  # mask -> list of values assigned
    for mask in profiles:
        assignment[mask] = []

    for v in range(m, 0, -1):
        best_gain = -1
        best_mask = None
        for mask, rem in profile_remaining.items():
            if rem == 0:
                continue
            gain = 0
            for i in range(n):
                if mask & (1 << i):
                    gain += abs(x[i] - r[i] - v) - abs(x[i] - r[i])
                # else no change
            if gain > best_gain:
                best_gain = gain
                best_mask = mask
        assignment[best_mask].append(v)
        profile_remaining[best_mask] -= 1
        for i in range(n):
            if best_mask & (1 << i):
                r[i] += v

    p = [0] * m
    for mask, vals in assignment.items():
        qs = profile_questions[mask]
        for idx, j in enumerate(qs):
            p[j] = vals[idx]

    print(*p)

t = int(input())
for _ in range(t):
    solve()

